mapper.select:
select uc.id,uc.cerNumber,c.title,c.startdate,c.expiredYear,c.trainUnit,uc.name,uc.image,uc.idCard from userscertificate uc
    join certificate c on uc.certificateId = c.id
where uc.cerNumber = #{number};

mapper.update:
update userscertificate
name = #{name}, idCard = #{idCard}, cerNumber = #{cerNumber}, image = #{image},
where id = #{id}
